class SamlResponseProcessor {
    public SamlAuthenticationResult processSamlResponse(String base64Response) throws Exception {
        if (!StringUtils.hasText(base64Response)) {
            throw new IllegalArgumentException("Missing SAMLResponse");
        }

        String xml = new String(Base64.getDecoder().decode(base64Response), StandardCharsets.UTF_8);
        Document document = parseXml(xml);

        XPath xpath = XPathFactory.newInstance().newXPath();
        String nameId = text(xpath, document, "//*[local-name()='Subject']/*[local-name()='NameID']/text()");
        String sessionIndex = text(xpath, document, "//*[local-name()='AuthnStatement']/@SessionIndex");
        String issueInstant = text(xpath, document, "/*[local-name()='Response']/@IssueInstant");

        Map<String, String> attributes = extractAttributes(document);

        if (!StringUtils.hasText(nameId)) {
            throw new IllegalArgumentException("Missing NameID");
        }

        return new SamlAuthenticationResult(nameId, sessionIndex, issueInstant, attributes);
    }

    private Map<String, String> extractAttributes(Document document) throws Exception {
        XPath xpath = XPathFactory.newInstance().newXPath();
        NodeList attributeNodes = (NodeList) xpath.evaluate("//*[local-name()='AttributeStatement']/*[local-name()='Attribute']", document, XPathConstants.NODESET);
        Map<String, String> attributes = new LinkedHashMap<>();
        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Node attribute = attributeNodes.item(i);
            Node nameAttr = attribute.getAttributes() != null ? attribute.getAttributes().getNamedItem("Name") : null;
            if (nameAttr == null) {
                continue;
            }
            String name = nameAttr.getNodeValue();
            NodeList values = attribute.getChildNodes();
            StringBuilder sb = new StringBuilder();
            for (int j = 0; j < values.getLength(); j++) {
                Node child = values.item(j);
                if ("AttributeValue".equals(localName(child)) && child.getTextContent() != null) {
                    if (sb.length() > 0) {
                        sb.append(",");
                    }
                    sb.append(child.getTextContent().trim());
                }
            }
            attributes.put(name, sb.toString());
        }
        return attributes;
    }

    private Document parseXml(String xml) throws ParserConfigurationException, IOException, org.xml.sax.SAXException {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);
        DocumentBuilder builder = factory.newDocumentBuilder();
        return builder.parse(new InputSource(new StringReader(xml)));
    }

    private String text(XPath xpath, Document document, String expr) throws Exception {
        String value = (String) xpath.evaluate(expr, document, XPathConstants.STRING);
        return value != null ? value.trim() : null;
    }

    private String localName(Node node) {
        return node == null ? null : node.getLocalName();
    }
}

